+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+export type WindowOrderBy = SQLWrapper | SQLWrapper[];
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: WindowOrderBy;
+	frame?: WindowFrame;
+}
+
+export class WindowFrame implements SQLWrapper {
+	constructor(private readonly kind: 'rows' | 'range', private readonly spec: WindowFrameSpec) {
+		validateFrame(spec);
+	}
+	getSQL(): SQL { return sql`${sql.raw(this.kind)} between ${this.spec.from} and ${this.spec.to}`; }
+}
+
+export interface WindowFrameSpec { from: FrameBoundary; to: FrameBoundary; }
+export class FrameBoundary implements SQLWrapper {
+	constructor(readonly position: number, private readonly text: string) {}
+	getSQL(): SQL { return sql.raw(this.text); }
+}
+
+export const unboundedPreceding = new FrameBoundary(Number.NEGATIVE_INFINITY, 'unbounded preceding');
+export const currentRow = new FrameBoundary(0, 'current row');
+export const unboundedFollowing = new FrameBoundary(Number.POSITIVE_INFINITY, 'unbounded following');
+
+function validateOffset(name: string, value: number): void {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+}
+export function preceding(value: number): FrameBoundary {
+	validateOffset('preceding', value);
+	return new FrameBoundary(-value, `${value} preceding`);
+}
+export function following(value: number): FrameBoundary {
+	validateOffset('following', value);
+	return new FrameBoundary(value, `${value} following`);
+}
+function validateFrame(spec: WindowFrameSpec): void {
+	if (spec.from.position > spec.to.position) throw new Error('Window frame "from" boundary must not be after "to" boundary');
+}
+export function rows(spec: WindowFrameSpec): WindowFrame { return new WindowFrame('rows', spec); }
+export function range(spec: WindowFrameSpec): WindowFrame { return new WindowFrame('range', spec); }
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly name: string, private readonly args: SQLWrapper[] = []) {}
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		const call = sql`${sql.raw(this.name)}(${sql.join(this.args, sql`, `)})`;
+		if (typeof spec === 'string') return sql`${call} over ${sql.identifier(spec)}`;
+		const parts: SQL[] = [];
+		if (spec.partitionBy) parts.push(sql`partition by ${sql.join(asArray(spec.partitionBy), sql`, `)}`);
+		if (spec.orderBy) parts.push(sql`order by ${sql.join(asArray(spec.orderBy), sql`, `)}`);
+		if (spec.frame) parts.push(spec.frame.getSQL());
+		return sql`${call} over (${sql.join(parts, sql` `)})`;
+	}
+	getSQL(): SQL<T> { return this.over(); }
+}
+function asArray<T>(value: T | T[]): T[] { return Array.isArray(value) ? value : [value]; }
+function position(name: string, value: number): SQLWrapper {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer; received ${value}`);
+	return sql.raw(String(value));
+}
+function value<T extends SQLWrapper>(value: T): T { return value; }
+
+export function rowNumber(): WindowFunction<number> { return new WindowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return new WindowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return new WindowFunction('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> { return new WindowFunction('ntile', [position('ntile', buckets)]); }
+export function percentRank(): WindowFunction<number> { return new WindowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return new WindowFunction('cume_dist'); }
