+	currentRow,
+	lag,
+	nthValue,
+	ntile,
+	preceding,
+	range,
+	rowNumber,
+	rows,
+	unboundedPreceding,
+	windowCount,
+	windowSum,
+} from '~/sql';
+
+const entries = pgTable('entries', { amount: integer(), group: integer() });
+
+test('window expressions and named windows compile without parameters for positions', () => {
+	const query = new QueryBuilder().select({
+		row: rowNumber().over('ordered'),
+		total: windowSum(entries.amount).over({ partitionBy: entries.group, orderBy: entries.amount, frame: rows({ from: unboundedPreceding, to: currentRow }) }),
+		previous: lag(entries.amount, 0).over(),
+		buckets: ntile(2).over(),
+		count: windowCount().over(),
+	}).from(entries).window('ordered', { orderBy: entries.amount }).orderBy(entries.amount);
+
+	expect(query.toSQL()).toEqual({
+		sql: 'select row_number() over "ordered", sum("entries"."amount") over (partition by "entries"."group" order by "entries"."amount" rows between unbounded preceding and current row), lag("entries"."amount", 0) over (), ntile(2) over (), count(*) over () from "entries" window "ordered" as (order by "entries"."amount") order by "entries"."amount"',
+		params: [],
+	});
+});
+
+test('window validation rejects invalid values', () => {
